from pwn import *
import os, sys
exe='/home/ctfplayer/ctf_files/popping_caps'
lib='/home/ctfplayer/ctf_files/libc.so.6'
context.binary=exe

def start():
    return process([exe], env={'LD_PRELOAD':lib})

def menu(io,c):
    io.sendlineafter(b'Your choice: ', str(c).encode())

def malloc(io,sz):
    menu(io,1)
    io.sendlineafter(b'How many: ', str(sz).encode())

def free_off(io,off):
    menu(io,2)
    io.sendlineafter(b'Whats in a free: ', str(off).encode())

def write_data(io,data):
    menu(io,3)
    io.sendafter(b'Read me in: ', data)

if __name__=='__main__':
    io=start()
    print(io.recvline().decode().strip())
    # interactive sequence from args? not used
    io.interactive()

